export async function handle_error_and_jsonify(event, state, options, error) {
	if (error instanceof HttpError) {
		// @ts-expect-error custom user errors may not have a message field if App.Error is overwritten
		return { message: 'Unknown Error', ...error.body };
	}

	if (__SVELTEKIT_DEV__ && typeof error == 'object') {
		fix_stack_trace(error);
	}

	const status = get_status(error);
	const message = get_message(error);

	return (
		(await with_request_store({ event, state }, () =>
			options.hooks.handleError({ error, event, status, message })
		)) ?? { message }
	);
}

function set_internal(name, value, options) {
	if (!normalized_url) {
		internal_queue.push(() => set_internal(name, value, options));
		return;
	}

	let path = options.path;

	if (!options.domain || options.domain === url.hostname) {
		path = resolve(normalized_url, path);
	}

	// Generate unique key for cookie storage
	const cookie_key = generate_cookie_key(options.domain, path, name);
	const cookie = { name, value, options: { ...options, path } };
	new_cookies.set(cookie_key, cookie);

	if (DEV) {
		const serialized = serialize(name, value, cookie.options);
		if (text_encoder.encode(serialized).byteLength > MAX_COOKIE_SIZE) {
			throw new Error(`Cookie "${name}" is too large, and will be discarded by the browser`);
		}

		cookie_paths[name] ??= new Set();

		if (!value) {
			cookie_paths[name].delete(path);
		} else {
			cookie_paths[name].add(path);
		}
	}
}

export function flush_eager_effects() {
	eager_effects_deferred = false;

	for (const effect of eager_effects) {
		// Mark clean inspect-effects as maybe dirty and then check their dirtiness
		// instead of just updating the effects - this way we avoid overfiring.
		if ((effect.f & CLEAN) !== 0) {
			set_signal_status(effect, MAYBE_DIRTY);
		}

		let dirty;

		try {
			dirty = is_dirty(effect);
		} catch {
			// Dirty-checking can evaluate derived dependencies and throw in cases where
			// parent effects are about to destroy this eager effect. Run the effect so
			// its own error handling can deal with transient failures.
			dirty = true;
		}

		if (dirty) {
			update_effect(effect);
		}
	}

	eager_effects.clear();
}

export function set(source, value, should_proxy = false) {
	if (
		active_reaction !== null &&
		// since we are untracking the function inside `$inspect.with` we need to add this check
		// to ensure we error if state is set inside an inspect effect
		(!untracking || (active_reaction.f & EAGER_EFFECT) !== 0) &&
		is_runes() &&
		(active_reaction.f & (DERIVED | BLOCK_EFFECT | ASYNC | EAGER_EFFECT)) !== 0 &&
		(current_sources === null || !current_sources.has(source))
	) {
		e.state_unsafe_mutation();
	}

	let new_value = should_proxy ? proxy(value) : value;

	if (DEV) {
		tag_proxy(new_value, /** @type {string} */ (source.label));
	}

	return internal_set(source, new_value, legacy_updates);
}

set(value, options) {
	this.#deferred?.reject(new Error('Aborted'));

	if (options?.instant || this.#current.v === undefined) {
		this.#task?.abort();
		this.#task = null;
		set(this.#current, set(this.#target, value));
		this.#last_value = value;
		return Promise.resolve();
	}

	if (options?.preserveMomentum) {
		this.#inverse_mass = 0;
		this.#momentum = options.preserveMomentum;
	}

	var d = (this.#deferred = deferred());
	d.promise.catch(noop);

	this.#update(value).then(() => {
		if (d !== this.#deferred) return;
		d.resolve(undefined);
	});

	return d.promise;
}

function graceful_shutdown(reason) {
	if (shutdown_timeout_id) return;

	// If a connection was opened with a keep-alive header close() will wait for the connection to
	// time out rather than close it even if it is not handling any requests, so call this first
	httpServer.closeIdleConnections();

	httpServer.close((error) => {
		// occurs if the server is already closed
		if (error) return;

		if (shutdown_timeout_id) {
			clearTimeout(shutdown_timeout_id);
		}
		if (idle_timeout_id) {
			clearTimeout(idle_timeout_id);
		}

		// @ts-expect-error custom events cannot be typed
		process.emit('sveltekit:shutdown', reason);
	});

	shutdown_timeout_id = setTimeout(() => httpServer.closeAllConnections(), shutdown_timeout * 1000);
}

async function server_fallback(url, route, error, status, replace_state) {
	if (url.origin === origin && url.pathname === location.pathname && !hydrated) {
		// We would reload the same page we're currently on, which isn't hydrated,
		// which means no SSR, which means we would end up in an endless loop
		return await load_root_error_page({
			status,
			error,
			url,
			route
		});
	}

	if (DEV && status !== 404) {
		console.error(
			'An error occurred while loading the page. This will cause a full page reload. (This message will only appear during development.)'
		);

		debugger; // eslint-disable-line
	}

	return await native_navigation(url, replace_state);
}

function has_changed(
	parent_changed,
	route_changed,
	url_changed,
	search_params_changed,
	uses,
	params
) {
	if (force_invalidation) return true;

	if (!uses) return false;

	if (uses.parent && parent_changed) return true;
	if (uses.route && route_changed) return true;
	if (uses.url && url_changed) return true;

	for (const tracked_params of uses.search_params) {
		if (search_params_changed.has(tracked_params)) return true;
	}

	for (const param of uses.params) {
		if (params[param] !== current.params[param]) return true;
	}

	for (const href of uses.dependencies) {
		if (invalidated.some((fn) => fn(new URL(href)))) return true;
	}

	return false;
}

addValue(checkboxValue: string | undefined) {
	if (!checkboxValue) return;
	if (!this.opts.value.current.includes(checkboxValue)) {
		const newValue = [...$state.snapshot(this.opts.value.current), checkboxValue];
		this.opts.value.current = newValue;
		if (arraysAreEqual(this.opts.value.current, newValue)) return;
		this.opts.onValueChange.current(newValue);
	}
}

removeValue(checkboxValue: string | undefined) {
	if (!checkboxValue) return;
	const index = this.opts.value.current.indexOf(checkboxValue);
	if (index === -1) return;
	const newValue = this.opts.value.current.filter((v) => v !== checkboxValue);
	this.opts.value.current = newValue;
	if (arraysAreEqual(this.opts.value.current, newValue)) return;
	this.opts.onValueChange.current(newValue);
}

loadImage(src: string, crossorigin?: CrossOrigin, referrerPolicy?: ReferrerPolicy) {
	if (this.opts.loadingStatus.current === "loaded") return;
	let imageTimerId: number;
	const image = new Image();

	image.src = src;
	if (crossorigin !== undefined) image.crossOrigin = crossorigin;
	if (referrerPolicy) image.referrerPolicy = referrerPolicy;

	this.opts.loadingStatus.current = "loading";
	image.onload = () => {
		imageTimerId = this.domContext.setTimeout(() => {
			this.opts.loadingStatus.current = "loaded";
		}, this.opts.delayMs.current);
	};
	image.onerror = () => {
		this.opts.loadingStatus.current = "error";
	};
	return () => {
		if (!imageTimerId) return;
		this.domContext.clearTimeout(imageTimerId);
	};
}

export function subsequent_fetch(resource, resolved, opts) {
	if (cache.size > 0) {
		const selector = build_selector(resource, opts);
		const cached = cache.get(selector);
		if (cached) {
			// https://developer.mozilla.org/en-US/docs/Web/API/Request/cache#value
			if (
				performance.now() < cached.ttl &&
				['default', 'force-cache', 'only-if-cached', undefined].includes(opts?.cache)
			) {
				return new Response(cached.body, cached.init);
			}

			cache.delete(selector);
		}
	}

	return DEV ? dev_fetch(resolved, opts) : window.fetch(resolved, opts);
}

export function extractScriptTags(
    source: string,
    html?: HTMLDocument
): { script?: TagInformation; moduleScript?: TagInformation } | null {
    const scripts = extractTags(source, 'script', html);
    if (!scripts.length) {
        return null;
    }

    const script = scripts.find(
        (s) => s.attributes['context'] !== 'module' && !('module' in s.attributes)
    );
    const moduleScript = scripts.find(
        (s) => s.attributes['context'] === 'module' || 'module' in s.attributes
    );
    return { script, moduleScript };
}

export function extractStyleTag(source: string, html?: HTMLDocument): TagInformation | null {
    const styles = extractTags(source, 'style', html);
    if (!styles.length) {
        return null;
    }

    // There can only be one style tag
    return styles[0];
}

export function isInsideMoustacheTag(text: string, tagStart: number, offset: number): boolean {
    const firstBraceIndex = text.indexOf('{', tagStart);
    if (firstBraceIndex > offset) {
        return false;
    }
    let index = firstBraceIndex;
    while (index < offset) {
        if (text.charCodeAt(index) !== braceStartCode) {
            index++;
            continue;
        }
        const result = scanMatchingBraces(text, index);
        if (!result.terminated) {
            return true;
        }
        index = result.endOffset;
    }
    return index > offset;
}

function to_iterator(source, name) {
	// intentionally using `in` because these could be inherited
	if ('next' in source && typeof source.next === 'function') {
		return source;
	}

	if (Symbol.asyncIterator in source && typeof source[Symbol.asyncIterator] === 'function') {
		return source[Symbol.asyncIterator]();
	}

	if (Symbol.iterator in source && typeof source[Symbol.iterator] === 'function') {
		return source[Symbol.iterator]();
	}

	throw new Error(
		`query.live '${name}' must return an Iterator, Iterable, AsyncIterator or AsyncIterable`
	);
}

export function rowsEqual(a, b) {
  if (a === b) return true;
  if (a === null || b === null) return false;
  if (!Array.isArray(a) || !Array.isArray(b)) return false;

  if (a.length !== b.length) return false;

  // Fast path: compare by row IDs first, assuming rows have stable IDs.
  for (let i = 0; i < a.length; i++) {
    if (a[i]?.id !== b[i]?.id) return false;
  }

  // If IDs match, do deep comparison of row objects
  // This catches cases where row data changed but ID stayed the same,
  // including changes in nested objects (e.g., "contact.company")
  for (let i = 0; i < a.length; i++) {
    const rowA = a[i];
    const rowB = b[i];

    // Fast path: same reference
    if (rowA === rowB) continue;

    // Deep comparison to handle nested objects and arrays
    if (!deepEqual(rowA, rowB)) return false;
  }

  return true;
}

class AccordionMultiState extends AccordionBaseState {
	readonly #value: AccordionMultiStateOpts["value"];
	readonly isMulti = true as const;

	constructor(props: AccordionMultiStateOpts) {
		super(props);
		this.#value = props.value;
		this.includesItem = this.includesItem.bind(this);
		this.toggleItem = this.toggleItem.bind(this);
	}

	includesItem(item: string): boolean {
		return this.#value.current.includes(item);
	}

	toggleItem(item: string): void {
		this.#value.current = this.includesItem(item)
			? this.#value.current.filter((v) => v !== item)
			: [...this.#value.current, item];
	}
}

watch(
	() => this.#pointerGraceArea,
	() => {
		const handleTrackPointerGrace = (e: PointerEvent) => {
			if (!this.#pointerGraceArea) return;
			const target = e.target;
			if (!isElement(target)) return;
			const pointerPosition = { x: e.clientX, y: e.clientY };
			const hasEnteredTarget =
				opts.triggerNode()?.contains(target) ||
				opts.contentNode()?.contains(target);
			const isPointerOutsideGraceArea = !isPointInPolygon(
				pointerPosition,
				this.#pointerGraceArea
			);

			if (hasEnteredTarget) {
				this.#removeGraceArea();
			} else if (isPointerOutsideGraceArea) {
				this.#removeGraceArea();
				opts.onPointerExit();
			}
		};
		const doc = getDocument(opts.triggerNode() ?? opts.contentNode());
		if (!doc) return;

		return on(doc, "pointermove", handleTrackPointerGrace);
	}
);

effect([open, preventScroll], ([$open, $preventScroll]) => {
	if (!isBrowser) return;

	if ($preventScroll && $open) unsubScroll = removeScroll();

	if ($open) {
		const contentEl = document.getElementById(ids.content.get());
		handleFocus({ prop: openFocus.get(), defaultEl: contentEl });
	}

	return () => {
		// we only want to remove the scroll lock if the dialog is not forced visible
		// otherwise the scroll removal is handled in the `destroy` of the `content` builder
		if (!forceVisible.get()) {
			unsubScroll();
		}
	};
});

effect(
	open,
	($open) => {
		if (!isBrowser || $open) return;
		handleFocus({
			prop: closeFocus.get(),
			defaultEl: activeTrigger.get(),
		});
	},
	{ skipFirstRun: true }
);

import { LocaleProviderRootContext } from '../../locale-provider/modules/root-context.js';
