async function onClick(performCopy, feedbackTimeout, portalled = false) {
  if (copyActive || animation === "fade-in") return;

  copyActive = true;
  copyPending = true;
  notify();

  try {
    await performCopy();
  } catch (error) {
    copyActive = false;
    copyPending = false;
    notify();
    throw error;
  }

  copyPending = false;
  animation = "fade-in";
  feedbackOpen = true;
  clearTimeout(timeout);
  timeout = setTimeout(() => {
    if (portalled) {
      feedbackOpen = false;
      animation = undefined;
      copyActive = false;
    } else {
      animation = "fade-out";
    }
    notify();
  }, feedbackTimeout);
  notify();
}

export function detectConfigs(cwd: string, config?: { relative: boolean }) {
	let cssPath: string | undefined;
	const paths = findFiles(cwd);
	for (const filepath of paths) {
		const filename = path.basename(filepath);
		if (STYLESHEETS.includes(filename)) {
			cssPath = config?.relative ? path.relative(cwd, filepath) : filepath;
			break;
		}
	}

	const tsconfigPath = findTSConfig(cwd);
	const resolvedTsconfigPath =
		tsconfigPath && config?.relative ? path.relative(cwd, tsconfigPath) : tsconfigPath;

	return {
		cssPath,
		tsconfigPath: resolvedTsconfigPath,
	};
}

const applyPosition = (
	clientXY: number,
	activeThumbIdx: number,
	start: number,
	end: number
) => {
	const percent = (clientXY - start) / (end - start);
	const val = percent * ($max - $min) + $min;

	if (val < $min) {
		updatePosition($min, activeThumbIdx);
	} else if (val > $max) {
		updatePosition($max, activeThumbIdx);
	} else {
		const step = $step;
		const min = $min;

		const currentStep = Math.floor((val - min) / step);
		const midpointOfCurrentStep = min + currentStep * step + step / 2;
		const midpointOfNextStep = min + (currentStep + 1) * step + step / 2;
		const newValue =
			val >= midpointOfCurrentStep && val < midpointOfNextStep
				? (currentStep + 1) * step + min
				: currentStep * step + min;

		if (newValue <= $max) {
			updatePosition(newValue, activeThumbIdx);
		}
	}
};

export function positionAt(
    offset: number,
    text: string,
    lineOffsets = getLineOffsets(text)
): Position {
    offset = clamp(offset, 0, text.length);

    let low = 0;
    let high = lineOffsets.length;
    if (high === 0) {
        return Position.create(0, offset);
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const lineOffset = lineOffsets[mid];

        if (lineOffset === offset) {
            return Position.create(mid, 0);
        } else if (offset > lineOffset) {
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    // low is the least x for which the line offset is larger than the current offset
    // or array.length if no line offset is larger than the current offset
    const line = low - 1;
    return Position.create(line, offset - lineOffsets[line]);
}

export function getScriptKindFromFileName(fileName: string): ts.ScriptKind {
    const ext = fileName.substr(fileName.lastIndexOf('.'));
    switch (ext.toLowerCase()) {
        case ts.Extension.Js:
            return ts.ScriptKind.JS;
        case ts.Extension.Jsx:
            return ts.ScriptKind.JSX;
        case ts.Extension.Ts:
            return ts.ScriptKind.TS;
        case ts.Extension.Tsx:
            return ts.ScriptKind.TSX;
        case ts.Extension.Json:
            return ts.ScriptKind.JSON;
        default:
            return ts.ScriptKind.Unknown;
    }
}

private async update(document: Document) {
    const uri = document.getURL();
    this.cancelStarted(uri);

    const tokenSource = new CancellationTokenSource();
    this.cancellationTokens.set(uri, tokenSource);

    const diagnostics = await this.getDiagnostics(
        { uri: document.getURL() },
        tokenSource.token
    );
    this.sendDiagnostics({
        uri: document.getURL(),
        diagnostics
    });

    tokenSource.dispose();

    if (this.cancellationTokens.get(uri) === tokenSource) {
        this.cancellationTokens.delete(uri);
    }
}

export async function* read_stream(reader, delimiter) {
	let done = false;
	let buffer = '';
	const decoder = new TextDecoder();

	while (true) {
		let split = buffer.indexOf(delimiter);
		while (split !== -1) {
			yield buffer.slice(0, split);
			buffer = buffer.slice(split + delimiter.length);
			split = buffer.indexOf(delimiter);
		}

		if (done) {
			if (buffer) {
				yield buffer;
			}
			return;
		}

		const chunk = await reader.read();
		done = chunk.done;
		if (chunk.value) {
			buffer += decoder.decode(chunk.value, { stream: true });
		}

		if (done) {
			buffer += decoder.decode();
		}
	}
}

export async function push(location: string): Promise<void> {
    if (!location || location.length < 1 || (location.charAt(0) != '/' && location.indexOf('#/') !== 0)) {
        throw Error('Invalid parameter location')
    }

    // Execute this code when the current call stack is complete
    await tick()

    // Note: this will include scroll state in history even when restoreScrollState is false
    history.replaceState(
        {
            ...history.state,
            __svelte_spa_router_scrollX: window.scrollX,
            __svelte_spa_router_scrollY: window.scrollY
        },
        ''
    )

    window.location.hash = (location.charAt(0) == '#' ? '' : '#') + location
}

export function clarify_devalue_error(event, error) {
	if (error.path) {
		return (
			`Data returned from \`load\` while rendering ${event.route.id} is not serializable: ${error.message} (${error.path}). ` +
			`If you need to serialize/deserialize custom types, use transport hooks: https://svelte.dev/docs/kit/hooks#Universal-hooks-transport.`
		);
	}

	if (error.path === '') {
		return `Data returned from \`load\` while rendering ${event.route.id} is not a plain object`;
	}

	// belt and braces — this should never happen
	return error.message;
}

function transformToTagInfo(matchedNode: Node, text: string): TagInformation {
    const start = matchedNode.startTagEnd ?? matchedNode.start;
    const end = matchedNode.endTagStart ?? matchedNode.end;
    const startPos = positionAt(start, text);
    const endPos = positionAt(end, text);
    const container = {
        start: matchedNode.start,
        end: matchedNode.end
    };
    const content = text.substring(start, end);

    return {
        content,
        attributes: parseAttributes(matchedNode.attributes),
        start,
        end,
        startPos,
        endPos,
        container
    };
}

async function fetchRegistry(urls: Array<URL | string>): Promise<unknown[]> {
	const proxyUrl = getEnvProxy();
	const proxy = proxyUrl ? createProxy({ url: proxyUrl }) : {};

	const loaders = urls.map(async (url) => {
		const response = await fetch(url, { ...proxy });
		if (!response.ok) {
			throw error(
				`Failed to fetch registry from ${url}: ${response.status} ${response.statusText}`
			);
		}

		try {
			return await response.json();
		} catch (e) {
			throw error(`Error parsing json response from ${url}: Error ${e}`);
		}
	});

	try {
		const results = await Promise.all(loaders);
		return results;
	} catch (e) {
		if (e instanceof CLIError) throw e;
		throw error(`Failed to fetch registry.`, e);
	}
}

export function getSupportedFontMarkers(sources: FontMarkerSource[]) {
	const supportedMarkers = new Set<string>();

	for (const source of sources) {
		for (const font of source.fonts ?? []) {
			const variable = font.font?.variable;
			if (!variable) {
				continue;
			}

			const marker = FONT_MARKERS_BY_VARIABLE[variable];
			if (marker) {
				supportedMarkers.add(marker);
			}
		}

		for (const vars of Object.values(source.cssVars ?? {})) {
			for (const key of Object.keys(vars ?? {})) {
				const marker = FONT_MARKERS_BY_VARIABLE[normalizeVariable(key)];
				if (marker) {
					supportedMarkers.add(marker);
				}
			}
		}
	}

	return Array.from(supportedMarkers);
}

slice(start = 0, end = this.size, contentType = this.type) {
	// https://github.com/nodejs/node/blob/a5f3cd8cb5ba9e7911d93c5fd3ebc6d781220dd8/lib/internal/blob.js#L240
	if (start < 0) {
		start = Math.max(this.size + start, 0);
	} else {
		start = Math.min(start, this.size);
	}

	if (end < 0) {
		end = Math.max(this.size + end, 0);
	} else {
		end = Math.min(end, this.size);
	}
	const size = Math.max(end - start, 0);
	const file = new LazyFile(
		this.name,
		contentType,
		size,
		this.lastModified,
		this.#get_chunk,
		this.#offset + start
	);

	return file;
}

function registerConsumer(spec) {
  const key = poolKey(spec.type, spec.options);
  let pool = pools.get(key);
  if (!pool) {
    const consumers = /** @type {Set<Consumer>} */ (new Set());
    const listener = (/** @type {Event} */ event) => {
      // Copy before iterating. Handlers may add or remove consumers mid-dispatch;
      // removed consumers should not run, same as native listeners.
      for (const consumer of [...consumers]) {
        if (consumers.has(consumer)) consumer.handler(event);
      }
    };
    pool = { type: spec.type, options: spec.options, listener, consumers };
    pools.set(key, pool);
    window.addEventListener(spec.type, listener, spec.options);
  }
  const consumer = { handler: spec.handler };
  pool.consumers.add(consumer);
  return { key, pool, consumer };
}

export async function detectPM(cwd: string, prompt: boolean): Promise<Agent | undefined> {
	const agent = (await detect({ cwd }))?.agent;

	// prompt for package manager
	if (!agent && prompt) {
		const options: Options = AGENT_NAMES.map((pm) => ({ value: pm, label: pm }));
		options.unshift({ label: "None", value: undefined });

		const userAgent = getUserAgent() ?? undefined; // replaces `null` for `undefined`
		const pm = await p.select({
			options,
			initialValue: userAgent,
			message: "Which package manager do you want to use?",
		});
		if (p.isCancel(pm)) {
			cancel();
		}

		return pm;
	}

	return agent;
}

function checkActive(el: ActiveNode): void {
    const matchesLocation = el.pattern.test(location)
    toggleClasses(el, el.className, matchesLocation)
    toggleClasses(el, el.inactiveClassName, !matchesLocation)
}

function toggleClasses(el: ActiveNode, className: string | undefined, shouldAdd: boolean): void {
    ;(className || '').split(' ').forEach((cls) => {
        if (!cls) {
            return
        }
        // Remove the class first
        el.node.classList.remove(cls)

        // If the pattern matches, then set the class
        if (shouldAdd) {
            el.node.classList.add(cls)
        }
    })
}

const pauseToastTimer = (currentToast: Toast<T>) => {
	if (currentToast.timeout !== null) {
		window.clearTimeout(currentToast.timeout);
	}
	currentToast.pausedAt = performance.now();
};
const restartToastTimer = (currentToast: Toast<T>) => {
	const pausedAt = currentToast.pausedAt ?? currentToast.createdAt;
	const elapsed = pausedAt - currentToast.createdAt - currentToast.pauseDuration;
	const remaining = currentToast.closeDelay - elapsed;
	currentToast.timeout = window.setTimeout(() => {
		removeToast(currentToast.id);
	}, remaining);
	currentToast.pauseDuration += performance.now() - pausedAt;
	currentToast.pausedAt = undefined;
};

export function parseStyleCss(css: string): Record<string, string> {
	const ast = parseCss(css);
	const styles: Record<string, string> = {};

	ast.walkRules((rule) => {
		// Extract class name from selector (e.g., ".cn-accordion-item" -> "cn-accordion-item")
		const selector = rule.selector;
		if (!selector.startsWith(".cn-")) return;

		const className = selector.slice(1); // Remove leading "."

		// Find @apply rules within this rule
		rule.walkAtRules("apply", (atRule) => {
			const applyValue = atRule.params.trim();
			if (applyValue) {
				// If there are multiple @apply rules, concatenate them
				if (styles[className]) {
					styles[className] += ` ${applyValue}`;
				} else {
					styles[className] = applyValue;
				}
			}
		});
	});

	return styles;
}

function resolvePeerDeps(
	dependencies: PackageJson["dependencies"],
	cwd: string
): ResolvedDependencies {
	const deps: ResolvedDependencies["deps"] = {};
	const versions: ResolvedDependencies["versions"] = {};

	for (const [name, version] of Object.entries(dependencies ?? {})) {
		const versioned = version ? `${name}@${version}` : name;
		const peers = (deps[versioned] ??= []);

		versions[name] = versioned;

		const pkg = getDependencyPackageInfo(cwd, name)?.pkg;
		if (!pkg) continue;

		const { peerDependencies = {}, peerDependenciesMeta = {} } = pkg;
		for (const [peerName] of Object.entries(peerDependencies)) {
			// ignores certain peer deps and optional peer deps
			if (IGNORE_DEPS.includes(peerName) || peerDependenciesMeta[peerName]?.optional)
				continue;
			peers.push(peerName);
		}
	}
	return { deps, versions };
}

export function resolveDepsFromImport(source: string, dependencies: ResolvedDependencies) {
	const depsFound: string[] = [];
	const simple = dependencies.versions[source] ? source : undefined;
	const depName =
		simple ??
		// considers deep imports
		Object.keys(dependencies.versions).find((dep) => source.startsWith(dep));

	if (depName && !IGNORE_DEPS.includes(depName)) {
		const versioned = dependencies.versions[depName]!;
		const peers = dependencies.deps[versioned];
		depsFound.push(versioned);
		peers?.forEach((dep) => depsFound.push(dep));
	}

	return depsFound;
}

